terraform {
  source = "tfr:///terraform-aws-modules/eks/aws//.?version=20.8.5"
}

include "root" {
  path   = find_in_parent_folders("root.hcl")
  expose = true
}

include "env" {
  path   = find_in_parent_folders("env.hcl")
  expose = true
}

inputs = {
  cluster_version                = "1.31"
  cluster_name                   = "${include.env.locals.name_prefix}-sportsbook-eks"
  vpc_id                         = include.root.locals.networks.dev.vpc_id
  subnet_ids                     = include.root.locals.networks.dev.vpc_private_subnets
  authentication_mode            = "API"
  cluster_endpoint_public_access = false
  # we manage log groups thru logs module
  create_cloudwatch_log_group = false
  cluster_enabled_log_types   = ["audit", "api", "authenticator", "scheduler", "controllerManager"]

  cluster_security_group_additional_rules = {
    ingress_malaga_https = {
      description = "Control plane access from Malaga Office"
      protocol    = "tcp"
      from_port   = 443
      to_port     = 443
      type        = "ingress"
      cidr_blocks = [include.root.locals.networks.external.ciklum_malaga_cidr]
    }
    ingress_tools_https = {
      description = "Control plane access from tools account"
      protocol    = "tcp"
      from_port   = 443
      to_port     = 443
      type        = "ingress"
      cidr_blocks = [include.root.locals.networks.tools.vpc_cidr_block]
    }
  }

  security_group_tags = {
    "karpenter.sh/discovery" = "${include.env.locals.name_prefix}-sportsbook-eks"
  }

  node_security_group_additional_rules = {
    ingress_istio_15017 = {
      description                   = "Cluster API - Istio Webhook namespace.sidecar-injector.istio.io"
      protocol                      = "TCP"
      from_port                     = 15017
      to_port                       = 15017
      type                          = "ingress"
      source_cluster_security_group = true
    }
    ingress_istio_15012 = {
      description                   = "Cluster API to nodes ports/protocols"
      protocol                      = "TCP"
      from_port                     = 15012
      to_port                       = 15012
      type                          = "ingress"
      source_cluster_security_group = true
    }
  }

  access_entries = {
    devops = {
      kubernetes_groups = []
      principal_arn     = "arn:aws:iam::512720242181:role/CiklumAdminNonProd"

      policy_associations = {
        cluster_admin = {
          policy_arn = "arn:aws:eks::aws:cluster-access-policy/AmazonEKSClusterAdminPolicy"
          access_scope = {
            type = "cluster"
          }
        }
      }
    }
    github_terraform = {
      kubernetes_groups = []
      principal_arn     = "arn:aws:iam::512720242181:role/OIDC_TerraformNonProdRole"

      policy_associations = {
        cluster_admin = {
          policy_arn = "arn:aws:eks::aws:cluster-access-policy/AmazonEKSClusterAdminPolicy"
          access_scope = {
            type = "cluster"
          }
        }
      }
    }
    github_deployment = {
      kubernetes_groups = []
      principal_arn     = "arn:aws:iam::512720242181:role/OIDC_NonProdRole"

      policy_associations = {
        cluster_admin = {
          policy_arn = "arn:aws:eks::aws:cluster-access-policy/AmazonEKSClusterAdminPolicy"
          access_scope = {
            type = "cluster"
          }
        }
      }
    }
  }

  cluster_addons = {
    eks-pod-identity-agent = {
      most_recent = true
      resolve_conflicts_on_create = "OVERWRITE"
      configuration_values        = jsonencode({
        nodeSelector = {
          "node-group" = "base"
        }
        tolerations = [
          {
            key    = "dedicated"
            value  = "basePods"
            effect = "NoSchedule"
          }
        ]
      })
    }
    vpc-cni = {
      resolve_conflicts_on_create = "OVERWRITE"
      resolve_conflicts_on_update = "OVERWRITE"
      addon_version               = "v1.21.1-eksbuild.7"
    }

    coredns = {
      resolve_conflicts_on_create = "OVERWRITE"
      resolve_conflicts_on_update = "OVERWRITE"
      addon_version               = "v1.11.4-eksbuild.33"
      configuration_values        = jsonencode({
        replicaCount = 2
        nodeSelector = {
          "node-group" = "base"
        }
        tolerations = [
          {
            key    = "dedicated"
            value  = "basePods"
            effect = "NoSchedule"
          }
        ]
      })
    }

    kube-proxy = {
      resolve_conflicts_on_create = "OVERWRITE"
      resolve_conflicts_on_update = "OVERWRITE"
      addon_version               = "v1.31.14-eksbuild.9"
    }

    metrics-server = {
      most_recent                 = true
      resolve_conflicts_on_create = "OVERWRITE"
      configuration_values        = jsonencode({
        nodeSelector = {
          "node-group" = "base"
        }
        tolerations = [
          {
            key    = "dedicated"
            value  = "basePods"
            effect = "NoSchedule"
          }
        ]
      })
    }

  }

  eks_managed_node_groups = {
    base = {
      instance_types    = ["t4g.large"]
      ami_type          = "AL2023_ARM_64_STANDARD"
      desired_size      = 2
      min_size          = 2
      max_size          = 4
      disk_size         = 50
      enable_monitoring = true
      # The cw-observability addon needs perms to create log groups
      # Either nodes or cloudwatch k8s SA needs perms to send logStreams
      iam_role_additional_policies = {
        CloudWatchAgentServerPolicy = "arn:aws:iam::aws:policy/CloudWatchAgentServerPolicy"
      }

      metadata_options = {
        http_put_response_hop_limit = 2
      }

      labels = {
        node-group = "base"
      }

      taints = {
        dedicated = {
          key     = "dedicated"
          value   = "basePods"
          effect  = "NO_SCHEDULE"
        }
      }

      timeouts = {
        create = null
        update = null
        delete = null
      }
    }
  }

  node_security_group_tags = {
    "karpenter.sh/discovery" = "${include.env.locals.name_prefix}-sportsbook-eks"
  }

  tags = include.env.locals.tags
}

# Logs groups must be created before eks in order to control the retention policy of the ones needed by the CW addons.
# Another way of doing this is by overriding the values of the addon amazon-cloudwatch-observability but the "performance"
# log group creation cannot be controlled by the values of it. In anycase this is the "cleaner" way.
dependency "logs" {
  config_path  = "../logs"
  skip_outputs = true
}

